import os
import pickle
from flask import Flask, request, jsonify
from flask_cors import CORS
from werkzeug.utils import secure_filename
import pdfplumber
from docx import Document
import numpy as np
import faiss
import google.generativeai as genai  # type: ignore
from dotenv import load_dotenv
import logging

load_dotenv()

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = Flask(__name__, static_folder='static', static_url_path='')
CORS(app)

UPLOAD_FOLDER = 'uploads'
FAISS_FOLDER = 'faiss_indexes'
ALLOWED_EXTENSIONS = {'pdf', 'docx'}

os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(FAISS_FOLDER, exist_ok=True)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

# Initialize Google Generative AI
api_key = os.getenv('GOOGLE_API_KEY')
if not api_key:
    logger.error("GOOGLE_API_KEY not found in environment variables!")
    logger.error(
        "Please add your Google AI Studio API key to Secrets with key 'GOOGLE_API_KEY'"
    )
    model = None
    embed_model = None
else:
    logger.info("Google API key found")
    try:
        genai.configure(api_key=api_key)  # type: ignore
        # Use current stable model - don't test to avoid wasting quota
        model = genai.GenerativeModel('gemini-2.0-flash-exp')  # type: ignore
        embed_model = 'models/text-embedding-004'
        logger.info("Google AI configured with gemini-2.0-flash-exp model")
    except Exception as e:
        logger.error(f"Error configuring Google AI: {str(e)}")
        model = None
        embed_model = None

current_document = {'text': '', 'chunks': [], 'filename': ''}

faiss_index = None
chunk_texts = []


def allowed_file(filename):
    return '.' in filename and filename.rsplit(
        '.', 1)[1].lower() in ALLOWED_EXTENSIONS


def extract_text_from_pdf(file_path):
    text = ""
    with pdfplumber.open(file_path) as pdf:
        for page in pdf.pages:
            page_text = page.extract_text()
            if page_text:
                text += page_text + "\n"
    return text


def extract_text_from_docx(file_path):
    doc = Document(file_path)
    text = ""
    for paragraph in doc.paragraphs:
        text += paragraph.text + "\n"
    return text


def count_words(text):
    return len(text.split())


def chunk_text(text, max_words=800):
    words = text.split()
    chunks = []

    current_chunk = []
    for word in words:
        current_chunk.append(word)
        if len(current_chunk) >= max_words:
            chunks.append(" ".join(current_chunk))
            current_chunk = []

    if current_chunk:
        chunks.append(" ".join(current_chunk))

    return chunks


def get_embedding(text):
    global embed_model

    if embed_model is None:
        raise Exception(
            "Google AI client not initialized. Please check your API key configuration in Secrets."
        )

    try:
        result = genai.embed_content(  # type: ignore
            model=embed_model,
            content=text,
            task_type="retrieval_document"
        )
        return result['embedding']
    except Exception as e:
        error_str = str(e).lower()
        if "quota" in error_str or "429" in error_str:
            raise Exception(
                "Google AI API quota exceeded. Please wait 1-2 minutes before trying again, or check your usage at https://aistudio.google.com/"
            )
        elif "api" in error_str and "key" in error_str:
            raise Exception(
                "Invalid Google AI API key. Please check your API key configuration in Secrets."
            )
        else:
            logger.error(f"Embedding error: {str(e)}")
            raise Exception(f"Embedding generation failed: {str(e)}")


def create_faiss_index(chunks):
    global faiss_index, chunk_texts

    if not chunks:
        return None

    chunk_texts = chunks
    embeddings = []

    for chunk in chunks:
        embedding = get_embedding(chunk)
        embeddings.append(embedding)

    embeddings_array = np.array(embeddings).astype('float32')  # type: ignore

    dimension = embeddings_array.shape[1]  # type: ignore
    faiss_index = faiss.IndexFlatL2(dimension)
    faiss_index.add(embeddings_array)  # type: ignore

    faiss_path = os.path.join(FAISS_FOLDER, 'index.faiss')
    chunks_path = os.path.join(FAISS_FOLDER, 'chunks.pkl')

    faiss.write_index(faiss_index, faiss_path)
    with open(chunks_path, 'wb') as f:
        pickle.dump(chunk_texts, f)

    return faiss_index


def search_similar_chunks(query, top_k=5):
    global faiss_index, chunk_texts

    if faiss_index is None or not chunk_texts:
        return []

    try:
        query_embedding = get_embedding(query)
        query_vector = np.array([query_embedding]).astype('float32')  # type: ignore

        distances, indices = faiss_index.search(query_vector, top_k)  # type: ignore

        results = []
        for idx in indices[0]:
            if idx < len(chunk_texts):
                results.append(chunk_texts[idx])

        return results
    except Exception:
        raise


@app.route('/')
def index():
    return app.send_static_file('index.html')


@app.route('/upload', methods=['POST'])
def upload_file():
    global current_document

    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400

    file = request.files['file']

    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    if file and file.filename and allowed_file(file.filename):
        try:
            filename = secure_filename(file.filename)
            file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            file.save(file_path)

            if filename.endswith('.pdf'):
                text = extract_text_from_pdf(file_path)
            elif filename.endswith('.docx'):
                text = extract_text_from_docx(file_path)
            else:
                return jsonify({'error': 'Unsupported file type'}), 400

            if not text or not text.strip():
                return jsonify({
                    'error':
                    'No text could be extracted from the document. The file may be empty, scanned, or image-based.'
                }), 400

            chunks = chunk_text(text, max_words=800)

            if not chunks:
                return jsonify({
                    'error':
                    'Document is too short to process. Please upload a longer document.'
                }), 400

            try:
                create_faiss_index(chunks)

                current_document = {
                    'text': text,
                    'chunks': chunks,
                    'filename': filename
                }
            except Exception as embedding_error:
                if "quota" in str(embedding_error).lower():
                    return jsonify({
                        'error':
                        f'Upload successful but embedding failed due to quota limits. {str(embedding_error)} Please try again later or upgrade your Google AI plan.'
                    }), 429
                else:
                    return jsonify({
                        'error':
                        f'Upload successful but indexing failed: {str(embedding_error)}'
                    }), 500

            return jsonify({
                'message':
                'File uploaded successfully',
                'filename':
                filename,
                'text_preview':
                text[:500] + '...' if len(text) > 500 else text,
                'total_chunks':
                len(chunks),
                'total_words':
                count_words(text)
            }), 200
        except Exception as e:
            return jsonify({'error': str(e)}), 500

    return jsonify(
        {'error':
         'Invalid file type. Only PDF and DOCX files are allowed.'}), 400


@app.route('/summarize', methods=['POST'])
def summarize():
    global current_document

    if not current_document['text']:
        return jsonify(
            {'error':
             'No document uploaded. Please upload a document first.'}), 400

    if model is None:
        return jsonify({
            'error':
            'Google AI client not initialized. Please check your API key configuration in Secrets.'
        }), 500

    try:
        text = current_document['text']

        max_text_length = 15000
        if len(text) > max_text_length:
            text = text[:max_text_length] + "..."

        prompt = f"""You are a helpful assistant that summarizes legal and policy documents. 
        Provide a clear, concise summary highlighting key points, requirements, and important clauses.

        Please summarize the following document:

        {text}"""

        try:
            response = model.generate_content(prompt)
            summary = response.text
        except Exception as api_error:
            if "quota" in str(api_error).lower() or "429" in str(api_error):
                raise Exception(
                    "API quota exceeded. Please wait a minute before trying again. The free tier has a limit of 2 requests per minute."
                )
            else:
                raise api_error

        return jsonify({
            'summary': summary,
            'document': current_document['filename']
        }), 200

    except Exception as e:
        logger.error(f"Summarization error: {str(e)}")
        return jsonify({'error': f'Summarization failed: {str(e)}'}), 500


@app.route('/ask', methods=['POST'])
def ask_question():
    global current_document

    if not current_document['text']:
        return jsonify(
            {'error':
             'No document uploaded. Please upload a document first.'}), 400

    if model is None:
        return jsonify({
            'error':
            'Google AI client not initialized. Please check your API key configuration in Secrets.'
        }), 500

    data = request.get_json()
    question = data.get('question', '')

    if not question:
        return jsonify({'error': 'No question provided'}), 400

    try:
        relevant_chunks = search_similar_chunks(question, top_k=5)

        if not relevant_chunks:
            return jsonify({
                'error':
                'Could not find relevant information in the document. This might be due to embedding service issues.'
            }), 404

        context = "\n\n".join(relevant_chunks)

        prompt = f"""You are a helpful assistant that answers questions about legal and policy documents. 
        Use only the provided context to answer questions accurately and cite relevant sections when possible.

        Context from document:
        {context}

        Question: {question}

        Please provide a detailed answer based on the context above."""

        try:
            response = model.generate_content(prompt)
            answer = response.text
        except Exception as api_error:
            if "quota" in str(api_error).lower() or "429" in str(api_error):
                raise Exception(
                    "API quota exceeded. Please wait a minute before trying again. The free tier has a limit of 2 requests per minute."
                )
            else:
                raise api_error

        return jsonify({
            'answer': answer,
            'question': question,
            'document': current_document['filename'],
            'chunks_used': len(relevant_chunks)
        }), 200

    except Exception as e:
        logger.error(f"Q&A error: {str(e)}")
        return jsonify({'error': f'Question answering failed: {str(e)}'}), 500


@app.route('/status', methods=['GET'])
def status():
    return jsonify({
        'document_loaded': bool(current_document['text']),
        'filename': current_document.get('filename', ''),
        'total_chunks': len(current_document.get('chunks', []))
    }), 200


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)

