* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    padding: 20px;
    color: #333;
}

.container {
    max-width: 1000px;
    margin: 0 auto;
}

header {
    text-align: center;
    color: white;
    margin-bottom: 40px;
    padding: 30px 20px;
}

header h1 {
    font-size: 2.5rem;
    margin-bottom: 10px;
    text-shadow: 2px 2px 4px rgba(0,0,0,0.2);
}

.subtitle {
    font-size: 1.1rem;
    opacity: 0.9;
}

.section {
    background: white;
    border-radius: 12px;
    padding: 30px;
    margin-bottom: 25px;
    box-shadow: 0 10px 30px rgba(0,0,0,0.2);
}

.section h2 {
    color: #667eea;
    margin-bottom: 10px;
    font-size: 1.5rem;
}

.section-description {
    color: #666;
    margin-bottom: 20px;
    font-size: 0.95rem;
}

.upload-area {
    border: 3px dashed #667eea;
    border-radius: 8px;
    padding: 40px;
    text-align: center;
    cursor: pointer;
    transition: all 0.3s ease;
    background: #f8f9ff;
}

.upload-area:hover {
    background: #f0f2ff;
    border-color: #764ba2;
}

.upload-icon {
    font-size: 3rem;
    margin-bottom: 15px;
}

.upload-area p {
    margin-bottom: 15px;
    color: #666;
}

.btn {
    padding: 12px 30px;
    border: none;
    border-radius: 6px;
    font-size: 1rem;
    cursor: pointer;
    transition: all 0.3s ease;
    font-weight: 600;
}

.btn-primary {
    background: #667eea;
    color: white;
}

.btn-primary:hover {
    background: #5568d3;
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(102, 126, 234, 0.3);
}

.btn-success {
    background: #10b981;
    color: white;
    margin-top: 10px;
}

.btn-success:hover {
    background: #059669;
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(16, 185, 129, 0.3);
}

.file-info {
    margin-top: 20px;
    padding: 15px;
    background: #f0fdf4;
    border-radius: 6px;
    border-left: 4px solid #10b981;
}

.status-message {
    margin-top: 15px;
    padding: 15px;
    border-radius: 6px;
    font-weight: 500;
}

.status-message.success {
    background: #d1fae5;
    border-left: 4px solid #10b981;
    color: #065f46;
}

.status-message.error {
    background: #fee2e2;
    border-left: 4px solid #ef4444;
    color: #991b1b;
}

.loader {
    border: 4px solid #f3f3f3;
    border-top: 4px solid #667eea;
    border-radius: 50%;
    width: 40px;
    height: 40px;
    animation: spin 1s linear infinite;
    margin: 20px auto;
}

@keyframes spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
}

.content-box {
    background: #f9fafb;
    border-radius: 8px;
    padding: 25px;
    min-height: 150px;
    line-height: 1.8;
    border: 1px solid #e5e7eb;
}

.placeholder {
    color: #9ca3af;
    text-align: center;
    font-style: italic;
}

.qa-input-area {
    margin-bottom: 20px;
}

#questionInput {
    width: 100%;
    padding: 15px;
    border: 2px solid #e5e7eb;
    border-radius: 8px;
    font-size: 1rem;
    font-family: inherit;
    resize: vertical;
    margin-bottom: 15px;
    transition: border-color 0.3s ease;
}

#questionInput:focus {
    outline: none;
    border-color: #667eea;
}

.qa-results {
    margin-top: 20px;
}

.qa-item {
    background: #f9fafb;
    border-radius: 8px;
    padding: 20px;
    margin-bottom: 15px;
    border-left: 4px solid #667eea;
}

.qa-question {
    font-weight: 600;
    color: #667eea;
    margin-bottom: 12px;
    font-size: 1.05rem;
}

.qa-answer {
    color: #374151;
    line-height: 1.8;
}

.qa-meta {
    margin-top: 12px;
    padding-top: 12px;
    border-top: 1px solid #e5e7eb;
    font-size: 0.85rem;
    color: #6b7280;
}

@media (max-width: 768px) {
    header h1 {
        font-size: 1.8rem;
    }

    .section {
        padding: 20px;
    }

    .upload-area {
        padding: 30px 15px;
    }

    .btn {
        width: 100%;
        margin-top: 10px;
    }
}

